const REQUIRED_MANIFEST_KEYS: ReadonlyArray<keyof SessionManifest> = [
  "session_id",
  "timestamp",
  "transcript_path",
  "transcript_hash",
  "transcript_size",
  "git_head",
  "branch",
  "files_changed",
  "excerpt",
];

export function shortSessionId(uuid: string): string {
  const stripped = uuid.replace(/-/g, "");
  if (stripped.length < 8) {
    throw new Error(
      `session_id is too short to shorten: expected at least 8 hex chars, got ${stripped.length}`
    );
  }
  return stripped.slice(0, 8);
}

export function validateManifest(
  data: unknown
): asserts data is SessionManifest {
  if (data === null || typeof data !== "object") {
    throw new Error("manifest must be an object");
  }
  const obj = data as Record<string, unknown>;

  for (const key of REQUIRED_MANIFEST_KEYS) {
    if (!(key in obj)) {
      throw new Error(`manifest is missing required key: ${key}`);
    }
  }

  if (!Array.isArray(obj.files_changed)) {
    throw new Error("manifest.files_changed must be an array");
  }

  const excerpt = obj.excerpt as Record<string, unknown> | null;
  if (
    !excerpt ||
    typeof excerpt !== "object" ||
    typeof excerpt.head !== "string" ||
    typeof excerpt.tail !== "string"
  ) {
    throw new Error("manifest.excerpt must be an object with string head and tail");
  }
}

export function readManifest(path: string): SessionManifest {
  const content = readFileSync(path, "utf-8");
  const { data } = parseFrontmatter<SessionManifest>(content);
  validateManifest(data);
  return data;
}

export function writeManifest(path: string, manifest: SessionManifest): void {
  validateManifest(manifest);
  const content = serializeFrontmatter(
    manifest as unknown as Record<string, unknown>,
    ""
  );
  writeFileSync(path, content);
}

export function readSummaryFrontmatter(path: string): {
  data: SessionSummaryFrontmatter;
  body: string;
} {
  const content = readFileSync(path, "utf-8");
  const { data, body } = parseFrontmatter<SessionSummaryFrontmatter>(content);
  return { data, body };
}

export function writeSummaryFrontmatter(
  path: string,
  frontmatter: SessionSummaryFrontmatter,
  body: string
): void {
  const content = serializeFrontmatter(
    frontmatter as unknown as Record<string, unknown>,
    body
  );
  writeFileSync(path, content);
}

import { createHash } from "node:crypto";
import { createReadStream } from "node:fs";

export async function sha256File(path: string): Promise<string | null> {
  return new Promise((resolve, reject) => {
    const hash = createHash("sha256");
    const stream = createReadStream(path, { highWaterMark: 64 * 1024 });

    stream.on("error", (err: NodeJS.ErrnoException) => {
      if (err.code === "ENOENT") {
        resolve(null);
        return;
      }
      reject(err);
    });
    stream.on("data", (chunk) => hash.update(chunk));
    stream.on("end", () => resolve(hash.digest("hex")));
  });
}
export type FileAction = "created" | "modified" | "deleted" | "renamed" | "unknown";

export interface FileChange {
  path: string;
  action: FileAction;
}

async function runGit(
  args: string[],
  cwd: string
): Promise<{ stdout: string; stderr: string; exitCode: number }> {
  const proc = Bun.spawn(["git", ...args], {
    cwd,
    stdout: "pipe",
    stderr: "pipe",
  });
  const [stdout, stderr] = await Promise.all([
    new Response(proc.stdout).text(),
    new Response(proc.stderr).text(),
  ]);
  const exitCode = await proc.exited;
  return { stdout, stderr, exitCode };
}

export async function headCommit(cwd: string): Promise<string | null> {
  const { stdout, exitCode } = await runGit(["rev-parse", "HEAD"], cwd);
  if (exitCode !== 0) return null;
  const sha = stdout.trim();
  return /^[0-9a-f]{40}$/.test(sha) ? sha : null;
}

export async function currentBranch(cwd: string): Promise<string | null> {
  const { stdout, exitCode } = await runGit(["branch", "--show-current"], cwd);
  if (exitCode !== 0) return null;
  const branch = stdout.trim();
  return branch.length > 0 ? branch : null;
}

function actionFromStatusCode(code: string): FileAction {
  switch (code[0]) {
    case "A":
      return "created";
    case "M":
      return "modified";
    case "D":
      return "deleted";
    case "R":
      return "renamed";
    default:
      return "unknown";
  }
}

export async function filesChangedSince(
  fromSha: string,
  cwd: string
): Promise<FileChange[]> {
  const { stdout, exitCode } = await runGit(
    ["diff", "--name-status", "--no-renames", `${fromSha}..HEAD`],
    cwd
  );
  if (exitCode !== 0) return [];
  return parseNameStatus(stdout);
}

function parseNameStatus(stdout: string): FileChange[] {
  const changes: FileChange[] = [];
  for (const line of stdout.split("\n")) {
    if (line.length === 0) continue;
    const [code, ...rest] = line.split("\t");
    if (!code || rest.length === 0) continue;
    const path = rest[rest.length - 1]!;
    changes.push({ path, action: actionFromStatusCode(code) });
  }
  return changes;
}

export async function uncommittedChanges(cwd: string): Promise<FileChange[]> {
  const { stdout, exitCode } = await runGit(
    ["status", "--porcelain=v1", "--untracked-files=all"],
    cwd
  );
  if (exitCode !== 0) return [];

  const changes: FileChange[] = [];
  for (const line of stdout.split("\n")) {
    if (line.length < 4) continue;
    const xy = line.slice(0, 2);
    const path = line.slice(3);
    let action: FileAction;
    if (xy === "??") action = "created";
    else if (xy.includes("A")) action = "created";
    else if (xy.includes("D")) action = "deleted";
    else if (xy.includes("R")) action = "renamed";
    else if (xy.includes("M")) action = "modified";
    else action = "unknown";
    changes.push({ path, action });
  }
  return changes;
}
import {
  closeSync,
  mkdirSync,
  openSync,
  readFileSync,
  unlinkSync,
  writeSync,
} from "node:fs";
import { dirname, join } from "node:path";

export interface LockOptions {
  staleMs?: number;
  retryMs?: number;
  retries?: number;
}

interface LockPayload {
  pid: number;
  createdAt: string;
}

const DEFAULTS: Required<LockOptions> = {
  staleMs: 5 * 60 * 1000,
  retryMs: 100,
  retries: 50,
};

export class LockBusyError extends Error {
  constructor(path: string) {
    super(`Lock is busy after retry budget exhausted: ${path}`);
    this.name = "LockBusyError";
  }
}

function tryAcquire(lockPath: string): boolean {
  try {
    const fd = openSync(lockPath, "wx");
    const payload: LockPayload = {
      pid: process.pid,
      createdAt: new Date().toISOString(),
    };
    writeSync(fd, JSON.stringify(payload));
    closeSync(fd);
    return true;
  } catch (err) {
    const code = (err as NodeJS.ErrnoException).code;
    if (code === "EEXIST") return false;
    if (code === "ENOENT") {
      mkdirSync(dirname(lockPath), { recursive: true });
      return tryAcquire(lockPath);
    }
