export interface Excerpt {
  head: string;
  tail: string;
}

const CODEPOINT_LIMIT = 1024;

interface ExtractedTurn {
  text: string;
}

function extractTurnsFromLine(line: string): ExtractedTurn[] {
  try {
    const obj = JSON.parse(line) as {
      type?: string;
      message?: { content?: unknown };
    };
    if (obj.type !== "human" && obj.type !== "assistant") return [];
    const content = obj.message?.content;
    if (typeof content === "string") {
      return content.length > 0 ? [{ text: content }] : [];
    }
    if (Array.isArray(content)) {
      const parts = content
        .filter((c): c is { type: string; text: string } =>
          typeof c === "object" && c !== null && (c as { type: string }).type === "text"
        )
        .map((c) => c.text)
        .filter((t) => typeof t === "string" && t.length > 0);
      return parts.length > 0 ? [{ text: parts.join("\n") }] : [];
    }
    return [];
  } catch {
    return [];
  }
}

/**
 * Extracts head (first ~1024 codepoints) and tail (last ~1024 codepoints)
 * of user/assistant text from a Claude Code JSONL transcript. Streaming —
 * memory-bounded regardless of transcript size.
 */
export async function extractExcerpt(path: string): Promise<Excerpt> {
  const head: string[] = [];
  let headCodepoints = 0;
  const tailBuffer: string[] = [];

  const stream = createReadStream(path, { encoding: "utf-8" });
  let buffer = "";

  try {
    for await (const chunk of stream as unknown as AsyncIterable<string>) {
      buffer += chunk;
      let newlineIdx: number;
      while ((newlineIdx = buffer.indexOf("\n")) !== -1) {
        const line = buffer.slice(0, newlineIdx);
        buffer = buffer.slice(newlineIdx + 1);
        processLine(line, head, tailBuffer);
        headCodepoints = countHeadCodepoints(head);
      }
    }
    if (buffer.length > 0) {
      processLine(buffer, head, tailBuffer);
    }
  } catch (err) {
    const code = (err as NodeJS.ErrnoException).code;
    if (code === "ENOENT") return { head: "", tail: "" };
    throw err;
  }

  const fullHead = head.join("\n");
  const fullTail = tailBuffer.join("\n");

  // If all content fits in 2*LIMIT codepoints, concatenate and put in head.
  const totalHeadCps = [...fullHead].length;
  const totalTailCps = [...fullTail].length;
  if (totalHeadCps <= CODEPOINT_LIMIT && totalTailCps <= CODEPOINT_LIMIT) {
    const combined = head.concat(tailBuffer).join("\n");
    return { head: combined, tail: "" };
  }

  return {
    head: sliceCodepoints(fullHead, 0, CODEPOINT_LIMIT),
    tail: sliceFromEnd(fullTail, CODEPOINT_LIMIT),
  };
}

function processLine(line: string, head: string[], tailBuffer: string[]): void {
  if (line.length === 0) return;
  const turns = extractTurnsFromLine(line);
  for (const turn of turns) {
    head.push(turn.text);
    tailBuffer.push(turn.text);
    // Keep tailBuffer bounded: if total codepoints exceed 4 * LIMIT, drop from front.
    while (countHeadCodepoints(tailBuffer) > CODEPOINT_LIMIT * 2) {
      tailBuffer.shift();
    }
  }
}

function countHeadCodepoints(parts: string[]): number {
  let total = 0;
  for (const p of parts) total += [...p].length;
  return total;
}

function sliceCodepoints(s: string, start: number, end: number): string {
  const out: string[] = [];
  let i = 0;
  for (const ch of s) {
    if (i >= start && i < end) out.push(ch);
    i++;
    if (i >= end) break;
  }
  return out.join("");
}

function sliceFromEnd(s: string, limit: number): string {
  const cps: string[] = [];
  for (const ch of s) cps.push(ch);
  if (cps.length <= limit) return cps.join("");
  return cps.slice(cps.length - limit).join("");
}

