    if (!assumeYes && !(await confirm())) return plan;

    for (const entry of plan.entries) {
      if (entry.state === "done") continue;
      await applyEntry(vaultPath, entry);
      entry.state = "done";
      writeJournal(journalPath, plan);
    }

    rmSync(journalPath, { force: true });
