    extracted: booleanField(data.extracted),
    decisions: arrayField(data.decisions) as Array<Record<string, unknown>>,
    open_threads: arrayField(data.open_threads) as Array<string | Record<string, unknown>>,
    tags: arrayField(data.tags) as string[],
    status: stringField(data.status),
  };
  const entireCheckpoint = stringField(data.entire_checkpoint);
  if (entireCheckpoint) manifest.entire_checkpoint = entireCheckpoint;

  writeManifest(manifestPath, manifest);
  writeSummaryFrontmatter(
